mapper.sql:
where coalesce(r.post_time, r.create_time) >= concat(#{query.beginDate}, ' 00:00:00')
  and coalesce(r.post_time, r.create_time) <= concat(#{query.endDate}, ' 23:59:59')

  and r.proj_id in
  #{projId}


  and (
    root.category_id in
    #{categoryId}
    or category.category_id in
    #{categoryId}
  )


  and r.node_id in
  #{nodeId}


  and r.post_by in
  #{approver}

mapper.select:
select r.record_id as recordId, r.bill_no as billNo, r.proj_name as projName, case r.bill_type when 'WORK_HOUR' then '工时' when 'REIMBURSEMENT' then '报销' else r.bill_type end as billTypeName, coalesce(root.category_name, category.category_name, r.category_name, '未分类') as categoryName, r.amount as amount, date_format(coalesce(r.post_time, r.create_time), '%Y-%m-%d') as postDate, r.post_by as approver from cost_posting_record r left join sys_cost_category category on category.category_id = r.category_id and category.del_flag = '0' left join sys_cost_category root on root.category_id = case when ifnull(category.parent_id, 0) = 0 then category.category_id else category.parent_id end and root.del_flag = '0' where
and r.bill_type = #{billType}
and ( coalesce(root.category_id, category.category_id, r.category_id) in #{categoryId} or r.category_id in #{categoryId} )
and r.post_by in #{approver}
order by coalesce(r.post_time, r.create_time) desc, r.record_id desc

select p.proj_id as projId, p.proj_name as projName, n.node_id as nodeId, n.node_no as nodeNo, n.node_name as nodeName, ifnull(n.node_budget, 0) as nodeBudget, ifnull(sum(case when then r.amount else 0 end), 0) as actualCost, ifnull(n.node_budget, 0) - ifnull(sum(case when then r.amount else 0 end), 0) as budgetBalance, case when ifnull(n.node_budget, 0) = 0 then 0 else round(ifnull(sum(case when then r.amount else 0 end), 0) / n.node_budget * 100, 2) end as execRate, date_format(n.plan_finish_date, '%Y-%m-%d') as planFinishDate from proj_wbs_node n inner join proj_info p on p.proj_id = n.proj_id and p.del_flag = '0' left join cost_posting_record r on r.node_id = n.node_id and r.proj_id = n.proj_id where n.del_flag = '0'
and n.node_id in #{nodeId}
group by p.proj_id, p.proj_name, n.node_id, n.node_no, n.node_name, n.node_budget, n.plan_finish_date order by p.proj_name asc, n.order_num asc, n.node_id asc
